-- a4e00000-0000-4000-8000-000000000000 動画別3問クイズ + 既存コース末(a4e90000-0000-4000-8000-000000000000)を末尾へ  自動生成
UPDATE public.lessons SET sort_order=1 WHERE id='a4e01000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=3 WHERE id='a4e02000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=5 WHERE id='a4e03000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=7 WHERE id='a4e04000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=9 WHERE id='a4e05000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=99 WHERE id='a4e90000-0000-4000-8000-000000000000';

ON CONFLICT (id) DO UPDATE SET course_id=EXCLUDED.course_id,title=EXCLUDED.title,content_type=EXCLUDED.content_type,estimated_minutes=EXCLUDED.estimated_minutes,sort_order=EXCLUDED.sort_order;

DELETE FROM public.quiz_questions WHERE lesson_id IN ('a4e01900-0000-4000-8000-000000000000','a4e02900-0000-4000-8000-000000000000','a4e03900-0000-4000-8000-000000000000','a4e04900-0000-4000-8000-000000000000','a4e05900-0000-4000-8000-000000000000');

